package fr.eni.buymystuff.controllers;

import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

@Controller
public class FrontTestController {

    @GetMapping("/test/login")
    public String login(Model model){

        return "/test/login";
    }
    @GetMapping("/test/test")
    public String accueil(Model model) {

        // Création d'une liste d'articles fake
        List<Article> articles = new ArrayList<>();

        articles.add(new Article(
                "data:image/jpeg;base64,",
                "Vélo Vintage",
                "Super vélo rétro en bon état",
                120.0,
                LocalDateTime.of(2026, 3, 20, 15, 30)
        ));
        articles.add(new Article(
                "data:image/jpeg;base64,",
                "Guitare Electrique",
                "Guitare électrique pour débutants",
                250.0,
                LocalDateTime.of(2026, 3, 20, 15, 30)
        ));
        articles.add(new Article(
                "data:image/jpeg;base64,",
                "Casque Audio",
                "Casque Bluetooth haut de gamme",
                75.0,
                LocalDateTime.of(2026, 3, 20, 15, 30)
        ));
        articles.add(new Article(
                "data:image/jpeg;base64,",
                "Test 4",
                "Casque 4 haut de gamme",
                75.0,
                LocalDateTime.of(2026, 3, 20, 15, 30)
        ));

        // On ajoute la liste au modèle
        model.addAttribute("articles", articles);

        // Retour du template Thymeleaf
        return "/test/test";
    }

    // Classe interne pour simplifier l'exemple
    public static class Article {
        private String imageUrl;
        private String nom;
        private String description;
        private double prix;
        private LocalDateTime  timer;

        public Article(String imageUrl, String nom, String description, double prix, LocalDateTime  timer) {
            this.imageUrl = imageUrl;
            this.nom = nom;
            this.description = description;
            this.prix = prix;
            this.timer = timer;
        }

        public String getImageUrl() { return imageUrl; }
        public String getNom() { return nom; }
        public String getDescription() { return description; }
        public double getPrix() { return prix; }
        public void setImageUrl(String imageUrl) {
            this.imageUrl = imageUrl;
        }
        public void setNom(String nom) {
            this.nom = nom;
        }
        public void setDescription(String description) {
            this.description = description;
        }
        public void setPrix(double prix) {
            this.prix = prix;
        }
        public LocalDateTime getTimer() {
            return timer;
        }
        public void setTimer(LocalDateTime  timer) {
            this.timer = timer;
        }
    }
}
